// src/api/api.js
import axios from 'axios';

const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:8080/api';

const api = axios.create({ baseURL: API_BASE });

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      const url = err.config?.url || '';
      const isAuthEndpoint = url.includes('/auth/login') || url.includes('/auth/register');
      if (!isAuthEndpoint) {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        if (window.location.pathname !== '/login' && window.location.pathname !== '/register') {
          window.location.href = '/login';
        }
      }
    }
    return Promise.reject(err);
  }
);

// Auth
export const authAPI = {
  register: (data) => api.post('/auth/register', data),
  login: (data) => api.post('/auth/login', data),
};

// 🔥 Products API
export const productAPI = {
  getAll: () => api.get('/products'),
  getFeatured: () => api.get('/products/featured'),
  getById: (id) => {
    const numericId = typeof id === 'string' ? parseInt(id, 10) : id;
    return api.get(`/products/${numericId}`);
  },
  getByCategory: (cat) => api.get(`/products/category/${cat}`),
  search: (q) => api.get(`/products/search?q=${encodeURIComponent(q)}`),
  getCategories: () => api.get('/products/categories'),

  // 🔥 Price Drop Endpoints
  getPriceDrops: () => api.get('/products/price-drops'),
  getPriceDropsByCategory: (category) => api.get(`/products/price-drops/category/${category}`),
  getPriceDropsSorted: () => api.get('/products/price-drops/sorted'),
  getPriceDropInfo: (id) => api.get(`/products/${id}/price-drop-info`),

  // CRUD
  create: (productData) => api.post('/products', productData),
  update: (id, productData) => api.put(`/products/${id}`, productData),
  triggerPriceDrop: (id, data) => api.patch(`/products/${id}/price-drop`, data),
  endPriceDrop: (id) => api.delete(`/products/${id}/price-drop`),
  delete: (id) => api.delete(`/products/${id}`),
};

// Cart
export const cartAPI = {
  get: () => api.get('/cart'),
  add: (data) => api.post('/cart', data),
  updateQty: (itemId, qty) => api.put(`/cart/${itemId}?quantity=${qty}`),
  remove: (itemId) => api.delete(`/cart/${itemId}`),
  clear: () => api.delete('/cart'),
  count: () => api.get('/cart/count'),
};

// Orders
export const orderAPI = {
  place: (data) => api.post('/orders', data),
  getAll: () => api.get('/orders'),
  getById: (id) => api.get(`/orders/${id}`),
  getStats: () => api.get('/orders/stats'),
  track: (num) => api.get(`/orders/track/${encodeURIComponent(num)}`),
  cancel: (id) => api.put(`/orders/${id}/cancel`),
  updateStatus: (id, status) => api.put(`/orders/${id}/status?status=${status}`),
};

// User
export const userAPI = {
  getProfile: () => api.get('/user/profile'),
  updateProfile: (data) => api.put('/user/profile', data),
  updateSettings: (data) => api.put('/user/settings', data),
  changePassword: (data) => api.put('/user/password', data),
  getAddresses: () => api.get('/user/addresses'),
  addAddress: (data) => api.post('/user/addresses', data),
  updateAddress: (id, data) => api.put(`/user/addresses/${id}`, data),
  deleteAddress: (id) => api.delete(`/user/addresses/${id}`),
};

// 🔔 Push Notifications API (NEW)
export const notificationAPI = {
  /**
   * Get VAPID public key for push subscription
   * @returns {Promise<{ publicKey: string }>}
   */
  getVapidPublicKey: () => api.get('/notifications/vapid-public-key').then(res => res.data.publicKey),

  /**
   * Save push subscription to backend
   * @param {Object} subscription - PushSubscription object from browser
   * @param {Object} metadata - Optional: userAgent, ipAddress
   * @returns {Promise<void>}
   */
  saveSubscription: async (subscription, metadata = {}) => {
    const payload = {
      endpoint: subscription.endpoint,
      keys: {
        p256dh: subscription.keys.p256dh,
        auth: subscription.keys.auth
      },
      userAgent: metadata.userAgent || navigator.userAgent,
      ipAddress: metadata.ipAddress || null
    };
    return api.post('/notifications/subscribe', payload);
  },

  /**
   * Delete push subscription(s)
   * @param {string|null} endpoint - Optional: specific endpoint to remove
   * @returns {Promise<void>}
   */
  deleteSubscription: (endpoint = null) => {
    const url = endpoint 
      ? `/notifications/unsubscribe?endpoint=${encodeURIComponent(endpoint)}`
      : '/notifications/unsubscribe';
    return api.delete(url);
  },

  /**
   * Send test push notification to current user
   * @returns {Promise<void>}
   */
  sendTestPush: () => api.post('/notifications/test'),

  /**
   * Get current user's active subscriptions (for device management)
   * @returns {Promise<Array<{ id: number, endpoint: string, userAgent: string, lastUsedAt: string }>>}
   */
  getSubscriptions: () => api.get('/notifications/subscriptions').then(res => res.data),

  /**
   * Update subscription metadata (e.g., mark as active/inactive)
   * @param {number} subscriptionId 
   * @param {Object} updates 
   * @returns {Promise<void>}
   */
  updateSubscription: (subscriptionId, updates) => 
    api.patch(`/notifications/subscriptions/${subscriptionId}`, updates),
};

// Reviews
export const reviewAPI = {
  getForProduct: (pid) => api.get(`/reviews/product/${pid}`),
  add: (pid, data) => api.post(`/reviews/product/${pid}`, data),
};

// Chat
export const chatAPI = {
  send: (data) => api.post('/chat', data),
};

// 🔔 Helper: Convert URL-safe base64 to Uint8Array (for VAPID key)
export const pushUtils = {
  urlBase64ToUint8Array: (base64String) => {
    const padding = '='.repeat((4 - (base64String.length % 4)) % 4);
    const base64 = (base64String + padding)
      .replace(/-/g, '+')
      .replace(/_/g, '/');
    const rawData = window.atob(base64);
    const outputArray = new Uint8Array(rawData.length);
    for (let i = 0; i < rawData.length; ++i) {
      outputArray[i] = rawData.charCodeAt(i);
    }
    return outputArray;
  },

  /**
   * Check if push notifications are supported in current browser
   */
  isSupported: () => 
    'serviceWorker' in navigator && 
    'PushManager' in window && 
    'Notification' in window,

  /**
   * Get current notification permission status
   */
  getPermission: () => 
    'Notification' in window ? Notification.permission : 'denied',
};

export default api;
